INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (100, "2030/01/01 14:59:59", 130011, 0.0, 2.1, "ヤマト", 3001100, 1, 3001, "2024/10/31 12:00:00", -416.5, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (101, "2030/01/01 14:59:59", 130011, 0.0, 5.68, "ヤマト", 3001101, 4, 3001, "2024/10/31 12:00:00", -416.5, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (102, "2030/01/01 14:59:59", 130011, 0.0, 0.0, "ヤマト", 3001102, 1, 3001, "2024/10/31 12:00:00", -416.5, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (100, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3002100, 1, 3002, "2024/10/31 12:00:00", -416.5, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (101, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3002101, 1, 3002, "2024/10/31 12:00:00", -416.5, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (102, "2030/01/01 14:59:59", 130211, 0.0, 8.53, "フブキ", 3002102, 5, 3002, "2024/10/31 12:00:00", -416.5, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (103, "2030/01/01 14:59:59", 130211, 0.0, 5.67, "フブキ", 3002103, 7, 3002, "2024/10/31 12:00:00", -416.5, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (104, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3002104, 1, 3002, "2024/10/31 12:00:00", -416.5, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (300, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3002300, 3, 3004, "2024/10/31 12:00:00", -416.5, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (301, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3002400, 7, 3005, "2024/10/31 12:00:00", -416.5, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (200, "2030/01/01 14:59:59", 130211, 0.0, 4.4, "フブキ", 3003200, 2, 3003, "2024/10/31 12:00:00", -416.5, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (201, "2030/01/01 14:59:59", 130211, 0.0, 0.0, "フブキ", 3003201, 7, 3003, "2024/10/31 12:00:00", -416.5, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (202, "2030/01/01 14:59:59", 130211, 0.0, 5.6, "フブキ", 3003202, 1, 3003, "2024/10/31 12:00:00", -416.5, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 2);
